      border: 1px solid rgba(255, 255, 255, 0.05);
      border-radius: 16px;
      padding: 25px;
      margin-bottom: 35px;
    }
    .card-title {
      color: #ffffff;
      font-size: 14px;
      font-weight: 800; 
      text-transform: uppercase;
      border-bottom: 1px solid rgba(255, 255, 255, 0.05);
      padding-bottom: 10px;
      margin-top: 0;
    }
    .data-row {
      margin-bottom: 12px;
      font-size: 14px;
    }
    .data-label {
      color: #71717a;
      display: inline-block;
      width: 120px;
      font-weight: 600;
    }
    .data-value {
      color: #e4e4e7;
    }
    .data-highlight {
      color: #F5C518;
      font-weight: 700;
    }
    .btn {
      display: inline-block;
      background-color: #F5C518;
      color: #060609 !important;
      font-weight: 800;
